@st.cache_data(ttl=86400, show_spinner=False)
def fetch_sp500_tickers_wiki_v2():
    """
    Descarga la lista oficial del S&P 500 desde Wikipedia usando
    un User-Agent de navegador para evitar el 403 Forbidden.
    """
    url = "https://en.wikipedia.org/wiki/List_of_S%26P_500_companies"
    headers = {
        "User-Agent": (
            "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
            "AppleWebKit/537.36 (KHTML, like Gecko) "
            "Chrome/124.0.0.0 Safari/537.36"
        ),
        "Accept-Language": "en-US,en;q=0.9",
    }

    try:
        resp = requests.get(url, headers=headers, timeout=10)
        resp.raise_for_status()
        html = io.StringIO(resp.text)
        tables = pd.read_html(html, attrs={"id": "constituents"}, flavor="lxml")
        df = tables[0]
        tickers = [str(t).replace(".", "-") for t in df["Symbol"].tolist()]
        if len(tickers) > 400:
            return tickers
    except Exception as e:
        print(f"[sp500] Fallo Wikipedia: {e}")

    return _FALLBACK_SP500
